public authenticate<StrategyOrStrategies extends string | Strategy | (string | Strategy)[]>(
  strategyOrStrategies: StrategyOrStrategies,
  optionsOrCallback?: AuthenticateOptions | AuthenticateCallback<StrategyOrStrategies>,
  callback?: AuthenticateCallback<StrategyOrStrategies>
): RouteHandlerMethod {
  let options: AuthenticateOptions | undefined
  if (typeof optionsOrCallback === 'function') {
    options = {}
    callback = optionsOrCallback
  } else {
    options = optionsOrCallback
  }

  return new AuthenticationRoute(this, strategyOrStrategies, options, callback).handler
}

function getPluginName (func) {
  const display = getDisplayName(func)
  if (display) {
    return display
  }

  // let's see if this is a file, and in that case use that
  // this is common for plugins
  const cache = require.cache
  // cache is undefined inside SEA
  if (cache) {
    const keys = Object.keys(cache)

    for (let i = 0; i < keys.length; i++) {
      const key = keys[i]
      if (cache[key].exports === func) {
        return key
      }
    }
  }

  // if not maybe it's a named function, so use that
  if (func.name) {
    return func.name
  }

  return null
}

function mergeDependencies (keyword, values, mergedSchema) {
  const mergedDependencies = {}
  for (const dependencies of values) {
    for (const propertyName of Object.keys(dependencies)) {
      if (mergedDependencies[propertyName] === undefined) {
        mergedDependencies[propertyName] = []
      }
      const mergedPropertyDependencies = mergedDependencies[propertyName]
      for (const propertyDependency of dependencies[propertyName]) {
        if (!mergedPropertyDependencies.includes(propertyDependency)) {
          mergedPropertyDependencies.push(propertyDependency)
        }
      }
    }
  }
  mergedSchema[keyword] = mergedDependencies
}

async function main() {
  // create fastify server instance
  const app = fastify();

  // initialize typeorm connection
  const connection = await createConnection();

  // register fastify-resty typeorm bootstraper
  app.register(typeorm, { connection });

  // bootstrap fastify-resty controllers using autoloader
  app.register(bootstrap, { entry: path.resolve(__dirname, 'api') });

  // start server listen on port 8080
  app.listen(8080, (err, address) => {
    if (err) {
      console.error(err);
      process.exit(1);
    }

    console.log(`Server is listening on ${address}`);
    console.log(app.printRoutes());
  });
}

insertPlaceholder(file: Pick<File, 'fieldname' | 'originalname' | 'encoding' | 'mimetype'>) {
  const placeholder = {
    fieldname: file.fieldname,
  }

  switch (this.strategy) {
    case 'NONE':
      break
    case 'VALUE':
      break
    case 'ARRAY':
      ;(this.request.files as Partial<File>[]).push(placeholder)
      break
    case 'OBJECT':
      if ((this.request.files as FilesObject)[file.fieldname]) {
        ;(this.request.files as FilesObject)[file.fieldname].push(placeholder)
      } else {
        ;(this.request.files as FilesObject)[file.fieldname] = [placeholder]
      }
      break
  }

  return placeholder
}

function ensureMetadata<T extends object>(target: T): asserts target is T & { [Symbol.metadata]: Record<symbol, unknown> } {
  // @ts-expect-error no types for Symbol.metadata yet
  if (!Object.prototype.hasOwnProperty.call(target, Symbol.metadata)) {
    const metadata = {};
    // @ts-expect-error no types for Symbol.metadata yet
    if (Symbol.metadata in target) {
      // @ts-expect-error no types for Symbol.metadata yet
      const parentMetadata = target[Symbol.metadata] as Record<PropertyKey, unknown>;
      Object.setPrototypeOf(metadata, parentMetadata);
    }
    // @ts-expect-error no types for Symbol.metadata yet
    Reflect.defineProperty(target, Symbol.metadata, {
      value: metadata,
      enumerable: false,
      configurable: true,
      writable: false,
    });
  }
}

export default function makeCreateUser({
  userRepository,
  userDomain,
  commandBus,
  eventBus,
}: Dependencies) {
  return {
    async handler({ payload }: HandlerAction<typeof createUserCommand>): Promise<CreateUserResult> {
      const user = userDomain.createUser(payload);
      try {
        await userRepository.insert(user);
        eventBus.emit(createUserEvent(user));
        return user.id;
      } catch (error: unknown) {
        if (error instanceof ConflictException) {
          throw new UserAlreadyExistsError(error);
        }
        throw error;
      }
    },
    init() {
      commandBus.register(createUserCommand.type, this.handler);
    },
  };
}

function xRay (request, reply) {
  // send back all the request properties
  return {
    id: request.id, // id assigned to the request in req-<progress>
    ip: request.ip, // the client ip address
    ips: request.ips, // proxy ip addressed
    hostname: request.hostname, // the client hostname
    protocol: request.protocol, // the request protocol
    method: request.method, // the request HTTP method
    url: request.url, // the request URL
    routerPath: request.routerPath, // the generic handler URL
    is404: request.is404 // the request has been routed or not
  }
}

async #getSubprocessWorkerHealth (worker, options) {
  // Bound the ITC call so a hung child cannot freeze the health loop.
  // On timeout we fall back to last-known ELU with a null heap reading so
  // that the loop keeps rescheduling and signals remain observable.
  const result = await executeWithTimeout(sendViaITC(worker, 'getHealth'), kHealthITCTimeoutMs, kTimeout)

  if (result === kTimeout) {
    const previousELU = options.previousELU ?? worker.performance.eventLoopUtilization()
    return { elu: 1, heapUsed: null, heapTotal: null, currentELU: previousELU }
  }

  const { currentELU, heapUsed, heapTotal } = result
  const previousELU = options.previousELU
  let elu = currentELU
  if (previousELU) {
    elu = performance.eventLoopUtilization(currentELU, previousELU)
  }

  return { elu: elu.utilization, heapUsed, heapTotal, currentELU }
}

async #setDispatcher (undiciConfig) {
  const config = this.#config

  const dispatcherOpts = { ...undiciConfig }
  const interceptors = [this.#meshInterceptor]

  if (config.httpCache) {
    this.#sharedHttpCache = await createSharedStore(this.#root, config.httpCache)
    interceptors.push(
      undiciInterceptors.cache({
        store: this.#sharedHttpCache,
        methods: config.httpCache.methods ?? ['GET', 'HEAD'],
        origins: parseOrigins(config.httpCache.origins),
        cacheByDefault: config.httpCache.cacheByDefault,
        type: config.httpCache.type
      })
    )
  }
  this.#dispatcher = new Agent(dispatcherOpts).compose(interceptors)
}

function patchLogging () {
  disablePinoDirectWrite()

  const kFormatForStderr = getPrivateSymbol(console, 'kFormatForStderr')

  // To avoid out of order printing on the main thread, instruct console to only print to the stdout.
  console._stderr = console._stdout
  console._stderrErrorHandler = console._stdoutErrorHandler

  // To recognize stderr in the main thread, each line is prepended with a special private Unicode character.
  const originalFormatter = console[kFormatForStderr]
  console[kFormatForStderr] = function (args) {
    let string = kStderrMarker + originalFormatter(args).replaceAll('\n', '\n' + kStderrMarker)

    if (string.endsWith(kStderrMarker)) {
      string = string.slice(0, -1)
    }

    return string
  }
}

async #handleNotification (messageEvent) {
  let request
  try {
    request = parseRequest(messageEvent.data)
  } catch (err) {
    this.#logger.error({ err: ensureLoggableError(err) }, 'Failed to parse the notification message.')
    return
  }

  try {
    const handler = this.getHandler(request.name)
    if (!handler) {
      throw new errors.HandlerNotFoundError(request.name)
    }

    await handler(request.data, { application: this.#id, message: request, notification: true })
  } catch (error) {
    this.#logger.error({ error }, `"Handler for the "${request.name}" message failed.`)
  }
}

export async function scanFolders(
  fastify: FastifyInstance,
  baseDir: string,
  current: string,
  prefix: string
): Promise<void> {
  const combined: string = path.join(baseDir, current);
  const combinedStat: fs.Stats = fs.statSync(combined);

  if (combinedStat.isDirectory()) {
    if (!path.basename(current).startsWith("_")) {
      for (const entry of fs.readdirSync(combined)) {
        await scanFolders(fastify, baseDir, path.join(current, entry), prefix);
      }
    }
  } else if (isAcceptableFile(combined, combinedStat)) {
    await autoload(fastify, combined, transformPathToUrl(current), prefix);
  }
}
